import{_ as a,o as t,c as s,a2 as n}from"./chunks/framework.D5wUhsuj.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md"}'),i={name:"guide/architecture.md"};function r(o,e,d,l,p,c){return t(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>AidiPanel is a server control panel for Ubuntu/Debian. It provisions a complete web stack and a small web panel to manage it. The design goals are a <strong>small footprint</strong>, <strong>fast responses</strong>, and <strong>isolation between sites</strong>.</p><h2 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Software</th><th>Role</th></tr></thead><tbody><tr><td>Web server</td><td>Nginx (mainline)</td><td>Serves sites, terminates TLS, runs FastCGI Cache</td></tr><tr><td>Runtime</td><td>PHP-FPM</td><td>One pool per site; default version 8.4</td></tr><tr><td>Database</td><td>MariaDB / MySQL</td><td>Application data</td></tr><tr><td>Cache</td><td>Redis</td><td>Object cache and session storage</td></tr><tr><td>TLS</td><td>Certbot (Let&#39;s Encrypt)</td><td>Certificates with auto-renewal</td></tr><tr><td>Firewall</td><td>UFW + Fail2ban</td><td>Network and brute-force protection</td></tr><tr><td>Panel</td><td>PHP web app</td><td>Web UI on port 8443</td></tr><tr><td>CLI</td><td>aidipanel</td><td>Manage the stack from SSH</td></tr></tbody></table><h2 id="request-flow" tabindex="-1">Request Flow <a class="header-anchor" href="#request-flow" aria-label="Permalink to &quot;Request Flow&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Browser</span></span>
<span class="line"><span>   |</span></span>
<span class="line"><span>   v</span></span>
<span class="line"><span>Nginx + FastCGI Cache -- hit --&gt; cached response (served from disk)</span></span>
<span class="line"><span>   |</span></span>
<span class="line"><span>  miss</span></span>
<span class="line"><span>   v</span></span>
<span class="line"><span>PHP-FPM (per-site pool, runs as the site user)</span></span>
<span class="line"><span>   |</span></span>
<span class="line"><span>   v</span></span>
<span class="line"><span>MariaDB / MySQL + Redis</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>Page caching is handled inside Nginx via FastCGI Cache, so there is no separate caching daemon. Caching is off by default per site and enabled explicitly.</p><h2 id="per-site-isolation" tabindex="-1">Per-Site Isolation <a class="header-anchor" href="#per-site-isolation" aria-label="Permalink to &quot;Per-Site Isolation&quot;">​</a></h2><p>Each site is provisioned with:</p><ul><li>a <strong>dedicated Linux user</strong> with <strong>no login shell</strong> (<code>/usr/sbin/nologin</code>) and a locked password;</li><li>a web root at <strong><code>/home/&lt;site-user&gt;/htdocs/&lt;domain&gt;</code></strong>;</li><li>its <strong>own PHP-FPM pool</strong> that runs as the site user.</li></ul><p>Nginx (<code>www-data</code>) reads each site&#39;s static files through group membership; the web root is <code>setgid</code> so files created by PHP keep the right group. Other site users are not in that group and cannot read the files. If one site&#39;s PHP is exploited, the process runs only as that site&#39;s user — this is <strong>per-user process and file isolation</strong>, not container-level sandboxing.</p><p>A <code>/home/&lt;site-user&gt;/.aidipanel-managed</code> marker (owned <code>root:root</code>) records which user/domain AidiPanel manages. Destructive operations (purge-delete) validate this marker before touching anything, so they can never remove an unmanaged account or directory.</p><h2 id="php-version-policy" tabindex="-1">PHP Version Policy <a class="header-anchor" href="#php-version-policy" aria-label="Permalink to &quot;PHP Version Policy&quot;">​</a></h2><p><code>/etc/aidipanel/php.conf</code> is the single source of truth:</p><div class="language-sh vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PHP_DEFAULT_VERSION</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;8.4&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PHP_AVAILABLE_VERSIONS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;8.2 8.3 8.4 8.5&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Only the default version is installed at provisioning time. Other supported versions are installed <strong>on-demand</strong> (<code>aidipanel php:install --version &lt;ver&gt;</code>), which keeps installs lean. The CLI sources this file; the panel reads it to list versions and checks the filesystem for install state.</p><h2 id="privileged-operations" tabindex="-1">Privileged Operations <a class="header-anchor" href="#privileged-operations" aria-label="Permalink to &quot;Privileged Operations&quot;">​</a></h2><p>The web panel runs as the dedicated <code>aidipanel</code> system user and cannot perform privileged actions directly. Nginx remains <code>www-data</code> and can only connect to the panel FPM socket. The panel invokes a single wrapper, <code>aidipanel-web-run</code>, through a narrowly scoped sudoers rule:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>aidipanel ALL=(root) NOPASSWD: /usr/local/sbin/aidipanel-web-run *</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The wrapper hard-codes an allowlist of permitted subcommands (defense in depth: the wrapper allowlist <strong>and</strong> the CLI&#39;s own validation). Arguments are passed as separate argv values, never interpolated into a shell string.</p><h2 id="panel-runtime" tabindex="-1">Panel Runtime <a class="header-anchor" href="#panel-runtime" aria-label="Permalink to &quot;Panel Runtime&quot;">​</a></h2><p>The panel runs under its own dedicated PHP-FPM service, <strong><code>aidipanel-fpm</code></strong>, on a private socket (<code>/run/aidipanel-fpm.sock</code>), isolated from the site PHP-FPM services so that reloading site pools never affects the panel.</p><h2 id="directory-map" tabindex="-1">Directory Map <a class="header-anchor" href="#directory-map" aria-label="Permalink to &quot;Directory Map&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td><code>/opt/aidipanel/</code></td><td>Panel application + storage</td></tr><tr><td><code>/etc/aidipanel/php.conf</code></td><td>PHP version policy</td></tr><tr><td><code>/home/&lt;site-user&gt;/htdocs/&lt;domain&gt;</code></td><td>Site web root</td></tr><tr><td><code>/etc/nginx/sites-available/</code></td><td>Vhost configs</td></tr><tr><td><code>/var/cache/nginx/fastcgi/</code></td><td>FastCGI cache files</td></tr><tr><td><code>/usr/local/bin/aidipanel</code></td><td>CLI</td></tr><tr><td><code>/usr/local/sbin/aidipanel-web-run</code></td><td>Privileged wrapper</td></tr></tbody></table>`,24)])])}const b=a(i,[["render",r]]);export{u as __pageData,b as default};
